proof fn phi_1_push_to_set_superset<A>(s: Seq<A>, x: A)
    ensures
        s.to_set().subset_of(s.push(x).to_set()),
{
    lemma_seq_push_to_set(s, x);
}

proof fn phi_2_push_duplicate_set_unchanged<A>(s: Seq<A>, x: A)
    requires
        s.contains(x),
    ensures
        s.push(x).to_set() == s.to_set(),
{
    lemma_seq_push_to_set(s, x);
    assert(s.to_set().insert(x) =~= s.to_set());
}

proof fn phi_3_push_to_set_contains_all_original<A>(s: Seq<A>, x: A, y: A)
    requires
        s.contains(y),
    ensures
        s.push(x).to_set().contains(y),
{
    lemma_seq_push_to_set(s, x);
}

proof fn phi_4_push_empty_singleton_set<A>(x: A)
    ensures
        Seq::<A>::empty().push(x).to_set() == set![x],
{
    lemma_seq_push_to_set(Seq::<A>::empty(), x);
    assert(Seq::<A>::empty().to_set() =~= Set::<A>::empty());
}

proof fn phi_5_push_to_set_len_not_preserved<A>(s: Seq<A>, x: A)
    requires
        s.contains(x),
        s.len() > 0,
    ensures
        s.push(x).len() == s.len() + 1,
        s.push(x).to_set() == s.to_set(),
{
    lemma_seq_push_to_set(s, x);
    assert(s.to_set().insert(x) =~= s.to_set());
}
